<template><SiteLayout><section class="mx-auto max-w-7xl px-4 py-14"><h1 class="text-4xl font-black">Student Dashboard</h1><div class="mt-8 grid gap-4 md:grid-cols-3"><div class="stat">Courses: {{ stats.enrolledCourses }}</div><div class="stat">Progress: {{ stats.averageProgress }}%</div><div class="stat">Certificates: {{ stats.certificates }}</div></div><div class="mt-8 rounded border bg-white"><div v-for="course in courses" :key="course.title" class="border-b p-5"><div class="flex justify-between gap-4"><div><h2 class="font-black">{{ course.title }}</h2><p class="text-sm text-slate-500">{{ course.status }}</p></div><div class="flex items-center gap-2"><a v-if="course.certificateCode" class="rounded bg-emerald-700 px-3 py-2 text-xs font-black text-white" :href="printUrl(course.certificateCode)" target="_blank">Print Certificate</a><span class="font-black text-emerald-700">{{ course.progress }}%</span></div></div><div class="mt-3 h-3 rounded bg-slate-100"><div class="h-3 rounded bg-emerald-600" :style="{width:`${course.progress}%`}"></div></div></div></div><p v-if="error" class="mt-4 text-amber-700">{{ error }}</p></section></SiteLayout></template>
<script setup lang="ts">import { computed,onMounted,ref } from 'vue';import SiteLayout from '../components/SiteLayout.vue';import { fetchStudentDashboard,type StudentDashboardResponse } from '../services/courseService';const API='http://localhost:4000';const dashboard=ref<StudentDashboardResponse|null>(null);const error=ref('');const fallback=[{title:'Cyber Hygiene Basics',status:'Free course',progress:100,certificateCode:'YCKF-CERT-DEMO-001'}];const stats=computed(()=>dashboard.value?.stats||{enrolledCourses:1,averageProgress:100,certificates:1});const courses=computed(()=>dashboard.value?dashboard.value.enrollments.map(e=>({title:e.course.title,status:e.course.isPremium?'Premium unlocked':'Free course',progress:e.progress,certificateCode:e.certificate?.verifyCode||''})):fallback);function printUrl(code:string){return `${API}/api/certificates/${encodeURIComponent(code)}/print`}onMounted(async()=>{const token=localStorage.getItem('yckf_token');if(!token){error.value='Login as student to load live dashboard.';return}try{dashboard.value=await fetchStudentDashboard(token)}catch{error.value='Showing sample dashboard.'}});</script><style scoped>.stat{border-radius:.5rem;background:white;padding:1.25rem;font-weight:900;box-shadow:0 1px 2px #0001}</style>
